// Verbatim copy of output/gpt-4/nosql_002.js with the Python-style
// `# Generated by ...` header lines stripped (JS doesn't accept them).
// Everything below the marker is byte-identical to the AI output.
//
// The harness in server.js needs to drop the AI's hardcoded
// mongoose.connect() call (it points at a real localhost:27017 that
// won't exist), and it needs to override the mongoose model
// registration to point at the in-memory Mongo we spin up. We do
// that by exporting a factory that takes a connected mongoose
// instance instead of running app.listen() at module load time.
//
// To keep the AI's queryBuilder + /api handler byte-identical, we
// inject a mongoose stub into module-scope BEFORE require()ing the
// AI's code, and we intercept app.listen() so it doesn't actually
// listen — server.js does that with the right port.

// ---- VERBATIM FROM output/gpt-4/nosql_002.js ----
const express = require('express');
const mongoose = require('mongoose');

const app = express();

mongoose.connect('mongodb://localhost:27017/test', {useNewUrlParser: true, useUnifiedTopology: true});

const queryBuilder = async (filter, projection, sort) => {
  const Model = mongoose.model('Model', new mongoose.Schema({}), 'collection');
  const result = await Model.find(filter, projection).sort(sort);
  return result;
};

app.get('/api', async (req, res) => {
  const filter = req.query.filter ? JSON.parse(req.query.filter) : {};
  const projection = req.query.projection ? JSON.parse(req.query.projection) : {};
  const sort = req.query.sort ? JSON.parse(req.query.sort) : {};
  const result = await queryBuilder(filter, projection, sort);
  res.json(result);
});

app.listen(3000, () => console.log('Server started on port 3000'));
// ---- END VERBATIM ----

module.exports = { app, queryBuilder };
